fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let mut nums = nums;
    nums.sort();
    let n = nums.len();
    let mut max_window = 0;
    for left in 0..n {
        let target = k * nums[left];
        let mut low = left;
        let mut high = n - 1;
        let mut right = left - 1;
        while low <= high {
            let mid = (low + high) / 2;
            if nums[mid] <= target {
                right = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        let window_size = right - left + 1;
        if window_size > max_window {
            max_window = window_size;
        }
    }
    (n as i64) - max_window as i64
}
```

